import React from "react";
import { useNavigate } from "react-router-dom";
import { LogOut, Zap, Users, Calendar, Briefcase } from "lucide-react";
import { useAuth } from "./AuthContext";

export default function Dashboard() {
  const navigate = useNavigate();
  const { user, logout } = useAuth();

  const handleLogout = () => {
    logout();
    navigate("/");
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <nav className="bg-white shadow">
        <div className="max-w-7xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <Zap className="w-6 h-6 text-blue-600" />
            <h1 className="text-2xl font-bold text-gray-900">Alumni Network</h1>
          </div>
          <button
            onClick={handleLogout}
            className="text-red-600 hover:bg-red-50 px-4 py-2 rounded"
          >
            <LogOut className="w-5 h-5" />
          </button>
        </div>
      </nav>

      <div className="max-w-7xl mx-auto px-4 py-8">
        <h2 className="text-3xl font-bold mb-8">Welcome, {user?.name}!</h2>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
          {[
            { label: "Connections", value: 142, icon: Users },
            { label: "Events", value: 5, icon: Calendar },
            { label: "Jobs", value: 28, icon: Briefcase },
            { label: "Messages", value: 3, icon: Users },
          ].map((stat, idx) => {
            const Icon = stat.icon;
            return (
              <div key={idx} className="bg-white rounded-lg shadow p-6">
                <Icon className="w-8 h-8 text-blue-600 mb-4" />
                <p className="text-gray-600 text-sm">{stat.label}</p>
                <p className="text-3xl font-bold text-gray-900">{stat.value}</p>
              </div>
            );
          })}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {[
            "Profile",
            "Messages",
            "Jobs",
            "Events",
            "Directory",
            "Settings",
          ].map((item) => (
            <button
              key={item}
              onClick={() => navigate(`/${item.toLowerCase()}`)}
              className="bg-white rounded-lg shadow p-6 hover:shadow-lg transition text-left"
            >
              <h3 className="font-semibold text-gray-900">{item}</h3>
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}
